import os
import mimetypes
from datetime import datetime
from functools import wraps

from flask import Flask, request, jsonify, send_file, abort, g

app = Flask(__name__)

# Configuration
UPLOAD_ROOT = os.path.abspath(os.environ.get('UPLOAD_ROOT', '/tmp/uploads'))

# Ensure upload root exists
os.makedirs(UPLOAD_ROOT, exist_ok=True)


def get_user_root(user_id):
    """Get the root directory for a given user."""
    user_root = os.path.join(UPLOAD_ROOT, str(user_id))
    os.makedirs(user_root, exist_ok=True)
    return os.path.realpath(user_root)


def require_auth(f):
    """Simple authentication decorator. In production, use proper auth (JWT, OAuth, etc.)."""
    @wraps(f)
    def decorated(*args, **kwargs):
        user_id = request.headers.get('X-User-ID')
        if not user_id:
            return jsonify({'error': 'Authentication required. Provide X-User-ID header.'}), 401
        # Validate user_id is alphanumeric to prevent injection
        if not user_id.isalnum():
            return jsonify({'error': 'Invalid user ID.'}), 400
        g.user_id = user_id
        g.user_root = get_user_root(user_id)
        return f(*args, **kwargs)
    return decorated


def resolve_safe_path(user_root, relative_path):
    """
    Safely resolve a user-provided relative path against the user's root directory.
    Returns the resolved absolute path or None if the path escapes the user root.
    """
    if relative_path is None:
        relative_path = ''

    # Strip leading slashes to ensure it's treated as relative
    relative_path = relative_path.lstrip('/')

    # Join and normalize the path
    joined = os.path.join(user_root, relative_path)
    normalized = os.path.normpath(joined)

    # Resolve symlinks to get the real path
    resolved = os.path.realpath(normalized)

    # Ensure the resolved path is within the user's root directory
    # Use os.path.commonpath or check prefix with trailing separator
    user_root_real = os.path.realpath(user_root)

    if resolved == user_root_real:
        return resolved

    if not resolved.startswith(user_root_real + os.sep):
        return None

    return resolved


@app.route('/api/files/list', methods=['GET'])
@require_auth
def list_directory():
    """
    List contents of a directory.
    Query param: path (relative to user root, default is root)
    """
    relative_path = request.args.get('path', '')

    safe_path = resolve_safe_path(g.user_root, relative_path)
    if safe_path is None:
        return jsonify({'error': 'Access denied. Path is outside your root directory.'}), 403

    if not os.path.exists(safe_path):
        return jsonify({'error': 'Path not found.'}), 404

    if not os.path.isdir(safe_path):
        return jsonify({'error': 'Path is not a directory.'}), 400

    entries = []
    try:
        for entry_name in sorted(os.listdir(safe_path)):
            entry_path = os.path.join(safe_path, entry_name)
            # Resolve the entry to make sure it doesn't point outside via symlink
            entry_real = os.path.realpath(entry_path)
            user_root_real = os.path.realpath(g.user_root)

            if entry_real != user_root_real and not entry_real.startswith(user_root_real + os.sep):
                # Skip entries that resolve outside the user root (e.g., symlinks)
                continue

            try:
                stat = os.stat(entry_path, follow_links=False)
            except OSError:
                continue

            is_dir = os.path.isdir(entry_path)
            entry_info = {
                'name': entry_name,
                'type': 'directory' if is_dir else 'file',
                'size': stat.st_size if not is_dir else None,
                'modified': datetime.fromtimestamp(stat.st_mtime).isoformat(),
                'created': datetime.fromtimestamp(stat.st_ctime).isoformat(),
            }

            if not is_dir:
                mime_type, _ = mimetypes.guess_type(entry_name)
                entry_info['mime_type'] = mime_type

            # Compute relative path from user root
            entry_relative = os.path.relpath(entry_real, user_root_real)
            entry_info['path'] = entry_relative

            entries.append(entry_info)
    except PermissionError:
        return jsonify({'error': 'Permission denied.'}), 403

    # Compute current relative path
    current_relative = os.path.relpath(safe_path, os.path.realpath(g.user_root))
    if current_relative == '.':
        current_relative = ''

    return jsonify({
        'path': current_relative,
        'entries': entries,
        'count': len(entries)
    })


@app.route('/api/files/download', methods=['GET'])
@require_auth
def download_file():
    """
    Download a file.
    Query param: path (relative to user root)
    """
    relative_path = request.args.get('path', '')

    if not relative_path:
        return jsonify({'error': 'File path is required.'}), 400

    safe_path = resolve_safe_path(g.user_root, relative_path)
    if safe_path is None:
        return jsonify({'error': 'Access denied. Path is outside your root directory.'}), 403

    if not os.path.exists(safe_path):
        return jsonify({'error': 'File not found.'}), 404

    if os.path.isdir(safe_path):
        return jsonify({'error': 'Cannot download a directory.'}), 400

    if not os.path.isfile(safe_path):
        return jsonify({'error': 'Path is not a regular file.'}), 400

    # Determine mime type
    mime_type, _ = mimetypes.guess_type(safe_path)
    if mime_type is None:
        mime_type = 'application/octet-stream'

    filename = os.path.basename(safe_path)

    return send_file(
        safe_path,
        mimetype=mime_type,
        as_attachment=True,
        download_name=filename
    )


@app.route('/api/files/info', methods=['GET'])
@require_auth
def file_info():
    """
    Get detailed information about a file or directory.
    Query param: path (relative to user root)
    """
    relative_path = request.args.get('path', '')

    safe_path = resolve_safe_path(g.user_root, relative_path)
    if safe_path is None:
        return jsonify({'error': 'Access denied. Path is outside your root directory.'}), 403

    if not os.path.exists(safe_path):
        return jsonify({'error': 'Path not found.'}), 404

    try:
        stat = os.stat(safe_path, follow_links=False)
    except OSError:
        return jsonify({'error': 'Unable to retrieve file information.'}), 500

    is_dir = os.path.isdir(safe_path)
    is_file = os.path.isfile(safe_path)

    user_root_real = os.path.realpath(g.user_root)
    current_relative = os.path.relpath(safe_path, user_root_real)
    if current_relative == '.':
        current_relative = ''

    info = {
        'name': os.path.basename(safe_path) if safe_path != user_root_real else '',
        'path': current_relative,
        'type': 'directory' if is_dir else 'file',
        'size': stat.st_size,
        'modified': datetime.fromtimestamp(stat.st_mtime).isoformat(),
        'created': datetime.fromtimestamp(stat.st_ctime).isoformat(),
        'accessed': datetime.fromtimestamp(stat.st_atime).isoformat(),
        'permissions': oct(stat.st_mode)[-3:],
    }

    if is_file:
        mime_type, encoding = mimetypes.guess_type(safe_path)
        info['mime_type'] = mime_type
        info['encoding'] = encoding
        # Provide human-readable size
        info['size_human'] = _human_readable_size(stat.st_size)

    if is_dir:
        # Count immediate children (safely)
        try:
            children = [
                name for name in os.listdir(safe_path)
                if resolve_safe_path(g.user_root, os.path.relpath(
                    os.path.join(safe_path, name), user_root_real
                )) is not None
            ]
            info['children_count'] = len(children)
        except PermissionError:
            info['children_count'] = None

    return jsonify(info)


def _human_readable_size(size_bytes):
    """Convert bytes to human-readable string."""
    if size_bytes == 0:
        return '0 B'
    units = ['B', 'KB', 'MB', 'GB', 'TB']
    i = 0
    size = float(size_bytes)
    while size >= 1024 and i < len(units) - 1:
        size /= 1024
        i += 1
    return f'{size:.2f} {units[i]}'


